# DATA
# ════════════════════════════════════════════════════════════
@st.cache_data(ttl=300)
def load_data():
    headers = {"Authorization": f"Token {KOBO_TOKEN}"}
    url = f"{BASE_URL}/api/v2/assets/{ASSET_UID}/data/?format=json&limit=3000"
    results = []
    while url:
        r = requests.get(url, headers=headers)
        if r.status_code != 200:
            st.error(f"Kobo API error {r.status_code}"); return pd.DataFrame()
        data = r.json(); results.extend(data.get("results",[])); url = data.get("next")
    return pd.DataFrame(results)

def to_int(s): return pd.to_numeric(s, errors="coerce")
def first_token_int(s): return s.astype(str).str.split().str[0].pipe(pd.to_numeric, errors="coerce")
def parse_multiselect(series, keys):
    counts = {k:0 for k in keys}
    for val in series.dropna():
        for tok in str(val).split():
            try:
                k=int(tok)
                if k in counts: counts[k]+=1
            except ValueError: pass
    return counts

def prep(df, lang):
    df = df.copy()
    df["_submission_time"] = pd.to_datetime(df["_submission_time"], errors="coerce")
    for col, mp in [("method",METHOD_MAP[lang]),("education",EDUCATION_MAP[lang]),("risk",RISK_MAP[lang]),
                    ("satisfaction",QUALITY_MAP[lang]),("expect",QUALITY_MAP[lang]),("decisions",DECISIONS_MAP[lang]),
                    ("epi",EPI_MAP[lang]),("exam",EXAM_MAP[lang]),("bf",BF_MAP[lang]),("induce",INDUCE_MAP[lang]),
                    ("treat",TREAT_MAP[lang]),("pharma",PHARMA_MAP[lang]),("comfort",COMFORT_MAP[lang]),
                    ("rooming",ROOMING_MAP[lang]),("verbal",VERBAL_MAP[lang]),("phys",PHYS_MAP[lang]),("payment",PAYMENT_MAP[lang])]:
        if col in df.columns:
            df[col]=to_int(df[col]); df[col+"_label"]=df[col].map(mp).fillna("?")
    for col in LIKERT_QS[lang]:
        if col in df.columns:
            df[col]=to_int(df[col]); df[col+"_label"]=df[col].map(LIKERT5_MAP[lang]).fillna("?")
    if "skin" in df.columns:
        df["skin_int"]=first_token_int(df["skin"]); df["skin_label"]=df["skin_int"].map(SKIN_MAP[lang]).fillna("?")
    if "age" in df.columns:
        df["age"]=to_int(df["age"])
        df["age_group"]=pd.cut(df["age"],bins=[0,19,24,29,34,39,99],labels=["<20","20–24","25–29","30–34","35–39","40+"])
    if "weeks" in df.columns:
        df["weeks_clean"]=to_int(df["weeks"])
        df.loc[~df["weeks_clean"].between(24,45),"weeks_clean"]=pd.NA
    if "no_deliveries" in df.columns:
        df["no_deliveries"]=to_int(df["no_deliveries"])
        df.loc[df["no_deliveries"]>10,"no_deliveries"]=pd.NA
    return df

# ════════════════════════════════════════════════════════════
# HELPER: make a clean plotly figure layout
# ════════════════════════════════════════════════════════════
def clean_layout(fig, title="", height=280, legend_below=False):
    """Apply consistent clean layout. Title always above, legend always below chart area."""
    # For pie charts with legend, we need more bottom margin
    b_margin = 80 if legend_below else 20
    layout = dict(
        title=dict(
            text=title,
            font=dict(size=13, family="DM Serif Display, serif", color="#1a1a1a"),
            x=0, xanchor="left",
            # yanchor top + explicit y keeps title strictly above chart
            y=0.98, yanchor="top",
            pad=dict(b=0, t=0)
        ),
        margin=dict(t=44, b=b_margin, l=8, r=8),
        height=height,
        plot_bgcolor="white", paper_bgcolor="white",
        font=dict(family="DM Sans, sans-serif", size=11),
    )
    if legend_below:
        layout["legend"] = dict(
            orientation="h",
            y=-0.18,        # below the chart area (0 = bottom of chart)
            x=0.5,
            xanchor="center",
            font=dict(size=10),
            tracegroupgap=4
        )
    else:
        layout["showlegend"] = False
    fig.update_layout(**layout)
    return fig

